const enContent: BlogContentBlock[] = [
  { type: 'paragraph', text: 'UI screenshot prompts work when they describe interface structure before visual style. Treat the prompt as a product brief: screen purpose, hierarchy, device frame, data density, active state, and what must stay readable.' },
  { type: 'heading', level: 2, text: 'TL;DR: write the screen before the style' },
  { type: 'list', items: ['Name the screen job before choosing style: dashboard, mobile flow, editor, checkout, onboarding, or marketing mockup.', 'Specify hierarchy: navigation, primary panel, secondary controls, cards, table, chart, empty state, and CTA position.', 'Use a reference screenshot only when layout continuity or product identity matters.', 'Keep final UI copy, accessibility checks, and production code outside the generated image.', 'In Vogue AI, use GPT Image 2 for control, Nano Banana for fast variants, and Midjourney for stylized product storytelling.'] },
  { type: 'heading', level: 2, text: 'Scenario matrix' },
  { type: 'table', headers: ['Job', 'Prompt pattern', 'Reference image', 'First failure to check'], rows: [['SaaS dashboard', 'Data hierarchy, sidebar, cards, charts, table density, desktop frame.', 'Useful when an existing product layout must stay recognizable.', 'Fake metrics, cluttered hierarchy, unreadable dense text.'], ['Mobile app screen', 'OS frame, thumb-safe controls, top bar, bottom navigation, active state.', 'Useful for redesigning an existing flow.', 'Too many controls, wrong navigation, tiny labels.'], ['Screenshot-to-code brief', 'Layout regions, spacing, component inventory, responsive intent.', 'Required when asking a tool or engineer to reproduce layout.', 'Pretty image with no component logic.'], ['Product marketing mockup', 'Device framing, reflection control, desk or hand context, visible screen hierarchy.', 'Optional unless the app screen must be accurate.', 'Decorative device shot that hides the UI.']] },
  { type: 'heading', level: 2, text: 'Prompt anatomy' },
  { type: 'list', items: ['Screen purpose: the user job and product context.', 'Layout regions: nav, content, controls, detail panel, and status areas.', 'Component inventory: cards, forms, table, chart, tabs, filters, buttons, and empty states.', 'Visual constraints: device frame, aspect ratio, theme, density, and reflection control.', 'Review rule: the first thing to inspect after generation.'] },
  { type: 'heading', level: 2, text: 'Copyable UI screenshot prompt blocks' },
  { type: 'paragraph', text: 'Copy one prompt block, replace the bracketed variables, and keep the rest stable for the first generation. The prompt blocks stay in English so they remain paste-ready in Vogue AI.' },
  { type: 'image', src: 'https://media.vogueai.net/blog/auto/ui-screenshot-prompts/43e96f7ae159-concept-couch-couple-camera-lcd-screen-nostalgia-1.jpg', alt: 'Screen-framing prompt example from the Vogue AI prompt library', caption: 'This first-party prompt-library image is useful near the copyable blocks because it demonstrates screen framing and readable visual hierarchy without repeating the article hero.' },
  { type: 'list', items: ['SaaS dashboard screenshot: High-resolution desktop web app screenshot for [product category], left sidebar navigation, top filter bar, primary analytics cards, one clean data table, one chart panel, clear information hierarchy, realistic SaaS spacing, neutral light theme, 16:9 browser frame, readable but generic UI labels, no brand logos, no distorted text.', 'Mobile app screen: Realistic iOS app screenshot for [app purpose], top navigation bar, thumb-safe primary action, bottom tab navigation, compact cards, one active state, clean product hierarchy, modern mobile UI spacing, 9:16 aspect ratio, readable generic labels, no fake brand logo, no watermark.', 'Screenshot-to-code layout brief: Convert this UI idea into a clean screenshot-style mockup: [screen purpose], exact regions include [navigation], [main content], [secondary panel], [empty or loading state], consistent 8px spacing rhythm, reusable card components, responsive web layout, no decorative filler, no final legal copy, browser screenshot framing.', 'Product mockup screenshot: Premium product marketing image for [app name], realistic device framing, visible interface hierarchy, soft reflection control, clean desk context, screen remains readable, 16:9 aspect ratio, no decorative filler, no watermark.'] },
  { type: 'heading', level: 2, text: 'Worked example: livestream commerce dashboard' },
  { type: 'heading', level: 3, text: 'Raw job' },
  { type: 'paragraph', text: 'You need a product mockup for an AI fashion livestream dashboard. The screen should show host controls, product queue, live metrics, and chat, but it should not pretend to be final code.' },
  { type: 'heading', level: 3, text: 'Prompt version 1' },
  { type: 'list', items: ['High-resolution desktop app screenshot for an AI fashion livestream control room, left sidebar with simple navigation icons, central live preview panel with a smiling fashion host, right product queue cards, bottom timeline controls, compact live chat column, premium ecommerce UI hierarchy, clean light interface, realistic browser screenshot, 16:9 aspect ratio, readable generic labels only, no brand logo, no distorted text.'] },
  { type: 'heading', level: 3, text: 'First-result diagnosis' },
  { type: 'paragraph', text: 'If the host looks good but the interface is fake, tighten the component inventory and remove vague style words. If the layout works but the copy breaks, ask for generic labels and add final text later.' },
  { type: 'heading', level: 2, text: 'Mistake and fix table' },
  { type: 'table', headers: ['Failure', 'Fix first', 'Avoid'], rows: [['UI looks decorative, not usable', 'Name the screen job and component inventory.', 'Adding more modern-app adjectives.'], ['Hierarchy is confusing', 'Specify primary, secondary, and tertiary regions.', 'Switching models before layout is clear.'], ['Text is broken', 'Use generic labels and add final copy later.', 'Asking for exact product copy in the image.'], ['Screenshot-to-code output is weak', 'Convert the image into components and states.', 'Treating a visual mockup as production code.'], ['Device frame hides the screen', 'Reduce reflections and require visible hierarchy.', 'Picking a pretty device angle over readability.']] },
  { type: 'heading', level: 2, text: 'Model fit inside Vogue AI' },
  { type: 'list', items: ['Use GPT Image 2 when instruction following and layout control matter most.', 'Use Nano Banana for quick variants, mobile-screen exploration, and lightweight image-to-image passes.', 'Use Midjourney when the screenshot is really a stylized product story or editorial app concept.', 'Keep the same prompt skeleton when switching models so you know what changed.'] },
  { type: 'heading', level: 2, text: 'Screenshot-to-code boundary' },
  { type: 'paragraph', text: 'A generated UI screenshot is a planning artifact, not production implementation. For screenshot-to-code work, pair the image with a component brief that names states, spacing, responsive behavior, and accessibility requirements.' },
  { type: 'heading', level: 2, text: 'FAQ' },
  { type: 'heading', level: 3, text: 'What is a UI screenshot prompt?' },
  { type: 'paragraph', text: 'It is a text brief that asks an image model to render an app, website, dashboard, or mobile screen as a screenshot or product mockup.' },
  { type: 'heading', level: 3, text: 'Can AI screenshots replace Figma or production code?' },
  { type: 'paragraph', text: 'No. They help with concept visuals and layout exploration, while final interaction logic, accessibility, exact copy, and code still need design and engineering review.' },
  { type: 'heading', level: 3, text: 'Should I use a reference screenshot?' },
  { type: 'paragraph', text: 'Use one when you need layout continuity, product identity, or a specific screen structure. For new concepts, text-only prompts are often faster.' },
  { type: 'heading', level: 3, text: 'How do I make screenshot-to-code prompts better?' },
  { type: 'paragraph', text: 'Name components, states, spacing, responsive behavior, and priority regions. A screenshot plus a component brief is stronger than a screenshot alone.' },
  { type: 'heading', level: 3, text: 'Which model should I try first?' },
  { type: 'paragraph', text: 'Start with GPT Image 2 when layout control matters, Nano Banana for fast variations, and Midjourney when the screenshot is more of a stylized product story.' },
  { type: 'heading', level: 3, text: 'Why does generated UI text look wrong?' },
  { type: 'paragraph', text: 'Image models can struggle with exact text. Use readable generic labels in the prompt, then add final copy in a design or code tool.' },
];

